var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"제길, 역시 이 정도 인원으로는 무리야……!","JPN":"くっそ、やはりこの人数では無理だ……！","ENG":"Dammit! We can't hold them off much longer...!","TWN":"可惡，這麼些人果然太勉強了……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"전원 파편을 주입해라! 잔해가 되어서라도 막아!","JPN":"全員、破片を注入しろ！　残骸になってでも防ぐんだ！","ENG":"All hands, inject yourselves with the Fragment! Become Remains and stop them!","TWN":"所有人給我注入碎片！就算變成殘骸也要阻止他們！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"소용없다고! 비켜!","JPN":"無駄だ、退け！","ENG":"It's no use! Outta my way!","TWN":"沒用！都給我讓開！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 서두르셔야 합니다!","JPN":"学部長、急いでください！","ENG":"Sir! You must hurry!","TWN":"院長，你得抓緊時間啊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"악기의 조율은 마쳤네.","JPN":"楽器の調律は終わった。","ENG":"The instrument is tuned now.","TWN":"樂器調好了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"준비하게. 지금부터 이걸로 차원계면에 손상을 입힐 테니까.","JPN":"準備を整えるように。今からこれで次元界面に損傷を与える。","ENG":"Be ready. I will now start damaging the dimension surface.","TWN":"做好準備。從現在開始，我會用它破壞次元裂縫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"고고학부장이 아티팩트로 차원에 균열을 일으키려 하고 있어요.","JPN":"考古学部長がアーティファクトを使って次元に亀裂を生じさせようとしています。","ENG":"The Dean of Archeology is using the Artifact to create a dimensional rift.","TWN":"考古學教授正試圖用人造神器製造次元裂縫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"버넷 요원, 서두르세요!","JPN":"エージェント・バーネット、時間がありません！","ENG":"Agent Burnett, make haste!","TWN":"伯內特，快點！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알고 있다고!","JPN":"分かってるって！","ENG":"I'm on it!","TWN":"我知道！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"커흑! 학부장님 어서……!","JPN":"がはっ……！　学部長、早く……！","ENG":"Kuh!! Sir, you mus–","TWN":"咳！院長，快……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어라? 고고학부장님. 악기도 불 줄 알아?","JPN":"あれ？　考古学部長、演奏もできるの？","ENG":"Huh? You know how to play an instrument, Dean of Archeology?","TWN":"咦？考古學教授，你還會吹樂器呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"젊었을 때 클라리넷을 다뤄본 적이 있지.","JPN":"若い頃、クラリネットを少しな。","ENG":"I played the clarinet when I was young.","TWN":"年輕的時候吹過單簧管。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"하지만 오보에는 처음일세. 연주가 시원치 않아도 양해 부탁하지.","JPN":"だがオーボエは初めてだ。上手くできなくても大目に見てくれよ。","ENG":"But an oboe is a first for me. So please excuse my horrible performance.","TWN":"但雙簧管還是第一次，即使演奏一般也請你們諒解。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"글쎄? 나는 악기 소리보단 총알 튀는 소리가 좋더라!","JPN":"ふうん、アタシは楽器の音より、弾丸の音の方が好きかな。","ENG":"Really? But I like the sound of bullets whizzing more than any instrument being played!","TWN":"這個嘛？比起樂器聲，我更喜歡子彈ㅕ咻～咻～的聲音！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"폭탄 터지는 소리랑~!","JPN":"爆弾の音とか～！","ENG":"And also the sound of bombs going BOOM!","TWN":"還有炸彈爆炸的聲音~！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런 젠장! 뭐하는 거야! 토끼녀!","JPN":"くっそ、何してんだよウサギ女！","ENG":"Agh, dammit! What are you doing, bunny girl?!","TWN":"該死！你在幹什麼！兔子女！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나까지 폭발에 휘말릴 뻔 했잖아!","JPN":"俺まで爆発に巻き込まれるとこだったじゃないか！","ENG":"I almost got caught in the blast!","TWN":"差點連我都捲進爆炸裡了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"헤헷, 아깝게 됐네~ 이전 싸움의 복수라고 생각해!","JPN":"えへっ、残念！　これは前回の仕返しだと思ってね！","ENG":"Hehe, so close! Think of it as payback for our previous fight!","TWN":"嘿嘿，好可惜啊~就當是給上一回報仇了吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 농담이 나와!?","JPN":"冗談言ってる場合か！","ENG":"Are you kidding me?!","TWN":"你還有心情開玩笑？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};